{"command": "cd /app/data/auto-opt/utils/llvm-98800 && cat <<'CODEEOF' | python $AGENT_TOOLS_DIR/apply_code.py write llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp 442 443

  // select c2, (select c1, a, b), (select c1, b, a) -> select (xor c1, c2), b, a
  if (TI->getOpcode() == Instruction::Select &&
      TI->hasOneUse() && FI->hasOneUse()) {
    auto *TISel = cast<SelectInst>(TI);
    auto *FISel = cast<SelectInst>(FI);
    Value *TICond = TISel->getCondition();
    Value *FICond = FISel->getCondition();
    if (TICond == FICond) {
      Value *TITrue = TISel->getTrueValue();
      Value *TIFalse = TISel->getFalseValue();
      Value *FITrue = FISel->getTrueValue();
      Value *FIFalse = FISel->getFalseValue();
      // select c2, (select c1, a, b), (select c1, b, a) -> select (xor c1, c2), b, a
      if (TITrue == FIFalse && TIFalse == FITrue) {
        Value *XorCond = Builder.CreateXor(TICond, SI.getCondition());
        return SelectInst::Create(XorCond, TIFalse, TITrue);
      }
      // select c2, (select c1, b, a), (select c1, a, b) -> select (xor c1, c2), a, b
      if (TITrue == FITrue && TIFalse == FIFalse) {
        // Both selects are identical, this simplifies to just the inner select
        return replaceInstUsesWith(SI, TI);
      }
    }
  }

CODEEOF"}

